import{_ as a,o as e,c as p,j as r,a as t,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const C=JSON.parse('{"title":"庞然巨牛","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/庞然巨牛.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/庞然巨牛.md"}'),d={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/庞然巨牛.md"};function n(s,b,l,_,i,c){return e(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"庞然巨牛",tabindex:"-1"},[t("庞然巨牛 "),r("a",{class:"header-anchor",href:"#庞然巨牛","aria-label":'Permalink to "庞然巨牛"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风024")])])],-1),o('<h1 id="庞然巨牛-1" tabindex="-1">庞然巨牛 <a class="header-anchor" href="#庞然巨牛-1" aria-label="Permalink to &quot;庞然巨牛&quot;">​</a></h1><p>庞然巨牛<br> C级随从<br> C+2000<br> 该随从可自由行动<br> 水牛型的怪物。6000AP。附带的牛角像机器人那样的装扮着。全身遍布重火器的同时防御力也很高，曾一度成为了龙骑的盾。召唤时除咆哮声提高以外自行移动之类的事都不做，只是在Zolda旁边站着的这样的场面也不少，契约镜怪物中唯一一个单独描述了战斗场景的。最终遭受了王蛇的“Doom&#39;s Day”而被消灭。<br> 初期的构想阶段中是真正的全身武器的机器人的设计理念，但因为其它的怪物都是以动物为原型而加入了牛的要素。然而为了与前一年播放的《百兽战队牙吠连者》作差别化，而不只是单纯以牛而是包含牛骨在内为原型。<br> 名称的由来是，意味着大的“magnu”与意味着巨人的“giga”</p><p>随从体积：7</p><p>随从属性：<br> 生理属性<br> 力量：9<br> 敏捷：11<br> 耐力：11<br> 心智属性<br> 智力：9<br> 感知：9<br> 决心：6<br> 互动属性<br> 风度：6<br> 操控：6<br> 沉着：6</p><p>随从技能：<br> 生理系<br> 运动8<br> 专业：反射5<br> 求生5<br> 专业：强韧5<br> 射击1<br> 专业：<br> 武技8<br> 专业：爪击8 炮击8</p><p>心智系<br> 学识5<br> 专业：身体掌握5<br> 器用1<br> 专业：<br> 手艺1<br> 专业：<br> 专注5<br> 专业：意志5</p><p>互动系<br> 洞察5<br> 专业：侦查5<br> 隐秘1<br> 专业：<br> 表达1<br> 专业：<br> 社交1<br> 专业</p><p>衍生属性值<br> 体积<br> 速度 （力量【9】+敏捷【11】+体积【7】+每1点敏捷上的附加获得3移动速度）=33<br> 先攻 （敏捷【11】+沉着【6】）= 17<br> 防御 （敏捷感知的平均值【10】+较高者的附加成功【2】）=10+2<br> 生命值 （耐力【11】+体积【7】+耐力附加【2】×5）=28<br> 意志力池 （决心【6】+沉着【6】+决心附加【1】×2）=14<br> 意志 （决心【6】+专注+意志【10+2】）= 16+2<br> 反射 （敏捷【9】+运动+反射【13+2】）= 22+2<br> 强韧 （耐力【11】+生存+强韧【10+2】）= 21+3<br> 侦查 （感知【9】+洞察+侦查【10+2】）= 19+2<br> 敏感范围 （感知【9】*20米+感知上的附加成功【1】*20米）=200米</p><p>攻击预设：<br> 近身爪击：9+8+8+5+3=33+4 范围：近战<br> 远程轰炸：11+8+8+5+3=35+5 范围：50米 【连射】 落点15米圆</p><p>防御预设：<br> 基础防御：10+2<br> 盔甲防御：2+2</p><p>【水牛型怪兽】：作为水牛型怪兽虽然庞然巨牛不是近战为主的怪兽但是体型依旧是比正常的怪兽要大上很多，所以庞然巨牛的体积为7，虽然不是近战为主但是作为怪兽其爪子本身依旧有着3L的伤害</p><p>【重武器集合】：虽然是水牛型怪兽但是庞然巨牛身上全是重武器，每一件拿出来都是极强的兵器，所以身上的武器有着3L的基础伤害，并且因为都是热武器所以自带【连射】特性并有着50米的攻击范围，并且因为多数为重武器所以会攻击落点15米直径的圆形范围内的所有敌人。又因为身上的重武器所以庞然巨牛有着2点盔甲防御和基于盔甲防御的1点附加成功</p><p>镜怪兽空间：因为镜怪兽天生便在镜世界之中生存，所以自然而然的学会了如何控制自己身体之上的反光面开辟一份独属于自己的10立方米空间的能力，其中不能装独立单位，使用者放入/取出物品至少是一个迅捷动作。</p><p>契约兽（庞然巨牛）下属武器：<br> 模仿契约兽庞然巨牛身上的特性然后靠着契约卡系统的能力制作而成的武器与护盾，其中蕴含着契约兽身体之中的特殊能力。在其下购买的武器和护盾在购买后都储存在庞然巨牛的体内，需要一个迅捷动作命令契约兽释放来取出和使用，画风为契约兽释放从天上飞下来你的武器和护盾自动装备在你的身上。</p><p>巨大发射器<br> C+1500<br> C级武器<br> Zolda所使用的有着可与“庞然巨牛”的两腕合体一样的形状的长距离攻击炮。2000AP。长度达到了超过Zolda身高的程度，因为大型武装的缘故而移动力下降。发射出的高压能量弹的威力非常高，一击便可以摧毁一栋高楼，初期由于强烈的反动而后退了数米的情景也有所展现。<br> 类型：炮<br> 基础属性：13L 高速5 破甲3 双手 无限子弹<br> 体积：5<br> 基础射程：200米<br> 【高压能量弹】：消耗一个整轮动作，进行一次攻击检定，这次攻击完全发挥该武器的所有能力发射出高压能量弹，而因为该武器过于沉重加上后坐力所以无法进行移动，这次攻击附带【能量武器】和【幻灭】特性。</p><p>巨大加农<br> C+2000<br> C级武器<br> Zolda与所使用的模仿了“庞然巨牛”的两脚的能量炮，以装着于Zolda的两肩的形式装备着。3000AP。因为过于厚重并且需要进行瞄准，所以在你进行使用该武器时无法进行移动。<br> 类型：炮<br> 基础属性：13L 高速5 破甲3 双手 无限子弹 自身无法自主移动<br> 体积：4<br> 【巨大加农】：巨大加农是一架能量炮，所以巨大加农发射出来的炮弹具有【能量武器】特性，并且因为巨大加农的巨大威力所以使用巨大加农的攻击会附带9加骰</p><p>巨大号角<br> C+1000<br> C级武器<br> Zolda所使用的模仿了“庞然巨牛”的头部两只角的手甲型格斗武器。附有类似于枪口的东西，是否有发射炮击的可能是不明的。2000AP。拍摄用的小道具有被制作出来，在摄影会等中有披露，但在剧中未使用。<br> 类型：手甲类型武器<br> 基础属性：11L 该武器伤害转换破防为破甲<br> 体积：2<br> 【号角之利】：这把武器主要靠着手甲上面的两只角作为主要打击敌人的方式，而这两只角可以轻松的击破敌人的护甲，所以该武器具有破甲5并且使得攻击检定获得1点器械加值<br> 【枪手近战好帮手】：巨大号角是铁兵这个枪兵唯一一个近战武器，所以在进行攻击检定时，肉搏检定的关键属性会被替换为敏捷，使得使用枪械的使用者可以更好的使用该武器进行近战来反制敌人。</p><p>巨大护甲<br> C+1000<br> C级盾牌<br> Zolda所使用的模仿了“庞然巨牛”的腹部的大型盾牌。3000GP。不只是防御，还能与“巨大发射器”组合，作为吸收反动的制动器使用。<br> 类型：重盾<br> 基础属性：11L 双手 格挡5<br> 体积：4<br> 【防卫之盾】：该盾牌最重要的用处就是——防卫盾牌后面的枪手，该武器会为使用者提供2点全吸收，使得后面的枪手受到的伤害更少。<br> 【兼容武器】：巨大护甲是铁兵最好的防卫武器，目的就是让使用者可以更好的搭配着枪械来进行使用，也可以兼容两把武器使得伤害得到更大的提升，在双手各持一把武器时，你可以将未加入攻击的另一把武器的基础属性一半与所有特性加入攻击中</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',20)])])}const f=a(d,[["render",n]]);export{C as __pageData,f as default};
